import sys
from itertools import combinations

def main():
    input = sys.stdin.read
    data = input().split()

    N = int(data[0])
    M = int(data[1])
    stands = data[2:2+N]

    # Check all combinations of stands to find the minimum set that covers all flavors
    for k in range(1, N+1):
        for combo in combinations(range(N), k):
            covered = set()
            for i in combo:
                for j in range(M):
                    if stands[i][j] == 'o':
                        covered.add(j)
            if len(covered) == M:
                print(k)
                return

if __name__ == "__main__":
    main()
